-- {"operators": "CTE,INNER_JOIN,AGGREGATE", "complexity": "high", "is_incremental": true, "has_nulls": false, "has_cast": false, "has_case": false, "tables": "ORDER_LINE,WAREHOUSE,DISTRICT", "refresh_type": "RECOMPUTE"}
WITH silver AS (SELECT OL_W_ID, OL_D_ID, AVG(OL_AMOUNT) AS avg_revenue, COUNT(*) AS line_count FROM ORDER_LINE GROUP BY OL_W_ID, OL_D_ID), gold AS (SELECT w.W_ID, w.W_NAME, s.OL_D_ID, s.avg_revenue, s.line_count FROM WAREHOUSE w JOIN silver s ON w.W_ID = s.OL_W_ID) SELECT g.W_ID, g.W_NAME, g.OL_D_ID, d.D_NAME, g.avg_revenue, g.line_count FROM gold g JOIN DISTRICT d ON g.W_ID = d.D_W_ID AND g.OL_D_ID = d.D_ID;
